return {
    ["line.bastion_forty_first_day_confront.1"] = { en = "You've counted the marks on the gate, I expect. Everyone does.", ja = "" },  -- TODO
    ["line.bastion_forty_first_day_confront.2"] = { en = "Forty-one. And every child in the order is taught that means forty-one days held.", ja = "" },  -- TODO
    ["line.bastion_forty_first_day_confront.3"] = { en = "It doesn't. It means forty-one of us said yes.", ja = "" },  -- TODO
    ["line.bastion_forty_first_day_confront.4"] = { en = "One mark each. She cut them herself, so nobody could ever say afterwards that they had been carried.", ja = "" },  -- TODO
    ["line.bastion_forty_first_day_confront.5"] = { en = "...", ja = "" },  -- TODO
    ["line.bastion_forty_first_day_confront.6"] = { en = "We still say it, girl. Every dawn, in your forms, in your order of ranks.", ja = "" },  -- TODO
    ["line.bastion_forty_first_day_confront.7"] = { en = "We shall hold.", ja = "" },  -- TODO
    ["line.bastion_forty_first_day_intro.1"] = { en = "They are still a company. Still drilled, still in our forms, still answering a muster. Forty-one of them.", ja = "" },  -- TODO
    ["line.bastion_forty_first_day_intro.2"] = { en = "Forty-one.", ja = "" },  -- TODO
    ["line.bastion_forty_first_day_intro.3"] = { en = "They kept every part of the oath except the part that cost anything.", ja = "" },  -- TODO
    ["line.bastion_forty_first_day_intro.4"] = { en = "Then they will be between her and us, and they will be very good at it.", ja = "" },  -- TODO
    ["line.bastion_forty_first_day_outro.1"] = { en = "Forty-one people said it in the same breath and then walked out through the gate.", ja = "" },  -- TODO
    ["line.bastion_forty_first_day_outro.2"] = { en = "It is the same sentence, {name}. Word for word. There is nothing you can do to a sentence to stop that happening to it.", ja = "" },  -- TODO
    ["line.bastion_forty_first_day_outro.3"] = { en = "...", ja = "" },  -- TODO
    ["line.bastion_forty_first_day_outro.4"] = { en = "No. There is one thing.", ja = "" },  -- TODO
    ["line.bastion_forty_first_day_outro.5"] = { en = "You can be somewhere the day it costs something.", ja = "" },  -- TODO
    ["line.bastion_forty_first_day_outro.6"] = { en = "Let's go. She is four miles up that road and she has been waiting fifteen years to be told she was right.", ja = "" },  -- TODO
    ["line.bastion_general_sloth_confront.1"] = { en = "Fifteen years of knights have held that line because they can say my name over their shields.", ja = "" },  -- TODO
    ["line.bastion_general_sloth_confront.10"] = { en = "I know what mine is worth.", ja = "" },  -- TODO
    ["line.bastion_general_sloth_confront.11"] = { en = "I chose it.", ja = "" },  -- TODO
    ["line.bastion_general_sloth_confront.2"] = { en = "Take it from them and the Watch empties tonight. Not in a year. Tonight.", ja = "" },  -- TODO
    ["line.bastion_general_sloth_confront.3"] = { en = "I have done more for that line as a lie than I ever did with a shield in my hands. Put your weapon down and think about it honestly, which is more than the order ever managed.", ja = "" },  -- TODO
    ["line.bastion_general_sloth_confront.4"] = { en = "...You're right.", ja = "" },  -- TODO
    ["line.bastion_general_sloth_confront.5"] = { en = "Yes.", ja = "" },  -- TODO
    ["line.bastion_general_sloth_confront.6"] = { en = "I have thought about it every mile of that road and I cannot answer you. Perhaps it does empty. Perhaps I am about to cost the line more than you ever did.", ja = "" },  -- TODO
    ["line.bastion_general_sloth_confront.7"] = { en = "But you never chose that post. It was issued to you. And when it came due you set it down, and you have spent fifteen years making that the truth about every post there has ever been, so that yours would stop being a thing you did.", ja = "" },  -- TODO
    ["line.bastion_general_sloth_confront.8"] = { en = "You. Girl. You have someone standing at your back.", ja = "" },  -- TODO
    ["line.bastion_general_sloth_confront.9"] = { en = "Look at them properly. No post is worth holding -- and that includes theirs.", ja = "" },  -- TODO
    ["line.bastion_general_sloth_intro.1"] = { en = "Past the gate that was opened from within.", ja = "" },  -- TODO
    ["line.bastion_general_sloth_intro.2"] = { en = "Sworn -- the order does not require this of you.", ja = "" },  -- TODO
    ["line.bastion_general_sloth_intro.3"] = { en = "No. It wouldn't.", ja = "" },  -- TODO
    ["line.bastion_general_sloth_intro.4"] = { en = "{name}. Whatever she says to me in there, I have already said it to myself on every mile of the road here. Don't worry about me.", ja = "" },  -- TODO
    ["line.bastion_general_sloth_intro.5"] = { en = "...Worry a little. But keep it to yourself.", ja = "" },  -- TODO
    ["line.bastion_general_sloth_outro.1"] = { en = "She was smaller than the shield made her.", ja = "" },  -- TODO
    ["line.bastion_general_sloth_outro.2"] = { en = "They will read her name at muster tomorrow. Nobody there will know, and I am not going to be the one who tells them -- not this month.", ja = "" },  -- TODO
    ["line.bastion_general_sloth_outro.3"] = { en = "Maybe the line empties. She may have been right about that. I will find out with everybody else.", ja = "" },  -- TODO
    ["line.bastion_general_sloth_outro.4"] = { en = "{name}.", ja = "" },  -- TODO
    ["line.bastion_general_sloth_outro.5"] = { en = "Fifteen years the order taught me to hold until relieved, and I never once noticed that it is a sentence about waiting for someone else to decide you may stop.", ja = "" },  -- TODO
    ["line.bastion_general_sloth_outro.6"] = { en = "I am not waiting to be relieved. I am not the relief either -- I tried that, it only meant running everywhere and arriving nowhere in particular.", ja = "" },  -- TODO
    ["line.bastion_general_sloth_outro.7"] = { en = "I am here, and it is you, and I picked it.", ja = "" },  -- TODO
    ["line.bastion_general_sloth_outro.8"] = { en = "We shall hold.", ja = "" },  -- TODO
    ["line.bastion_greywatch_intro.1"] = { en = "Greywatch. Every knight in the order recites a doctrine named after that fort and I have never once stood in it.", ja = "" },  -- TODO
    ["line.bastion_greywatch_intro.2"] = { en = "There is nothing there, Sworn. It has stood empty fifteen years. The roof is in the courtyard.", ja = "" },  -- TODO
    ["line.bastion_greywatch_intro.3"] = { en = "Then it won't mind me walking it.", ja = "" },  -- TODO
    ["line.bastion_greywatch_intro.4"] = { en = "I want to see the ground she chose to die on. That is all. Humour me, {name}.", ja = "" },  -- TODO
    ["line.bastion_greywatch_outro.1"] = { en = "{name}. The bar. Look at the bar.", ja = "" },  -- TODO
    ["line.bastion_greywatch_outro.2"] = { en = "It's on the ground. On the INSIDE. You cannot lift a gate-bar from the wrong side of a gate -- that is the entire point of a bar.", ja = "" },  -- TODO
    ["line.bastion_greywatch_outro.3"] = { en = "Someone in this fort opened it.", ja = "" },  -- TODO
    ["line.bastion_greywatch_outro.4"] = { en = "She died holding a gateway that was already standing open behind her. Fifteen years and nobody in the order has said that out loud.", ja = "" },  -- TODO
    ["line.bastion_greywatch_outro.5"] = { en = "They let her name carry a doctrine and they never told a single one of us she was betrayed.", ja = "" },  -- TODO
    ["line.bastion_greywatch_outro.6"] = { en = "I want the file. Whatever the archive kept on Greywatch, I want it in my hands.", ja = "" },  -- TODO
    ["line.bastion_held_position_intro.1"] = { en = "A watchpost east of the river. There is nothing behind it worth defending -- the villages moved off that land twenty years ago.", ja = "" },  -- TODO
    ["line.bastion_held_position_intro.2"] = { en = "The garrison has been told, in writing, that they may stand down.", ja = "" },  -- TODO
    ["line.bastion_held_position_intro.3"] = { en = "And they haven't.", ja = "" },  -- TODO
    ["line.bastion_held_position_intro.4"] = { en = "They have not.", ja = "" },  -- TODO
    ["line.bastion_held_position_intro.5"] = { en = "Good.", ja = "" },  -- TODO
    ["line.bastion_held_position_intro.6"] = { en = "Come and stand with them, {name}. You have been taking my word for what the order is. Today you can watch it done properly.", ja = "" },  -- TODO
    ["line.bastion_held_position_outro.1"] = { en = "The sergeant asked me when the relief was due. I told him I didn't know.", ja = "" },  -- TODO
    ["line.bastion_held_position_outro.2"] = { en = "He said that was fine.", ja = "" },  -- TODO
    ["line.bastion_held_position_outro.3"] = { en = "He said it the way you'd say the weather was fine, {name}. Not bravely. It had just stopped being a question a long time ago.", ja = "" },  -- TODO
    ["line.bastion_held_position_outro.4"] = { en = "There is nothing behind that post. There has not been for twenty years. They know that better than the archive does -- they can see the empty fields from the wall.", ja = "" },  -- TODO
    ["line.bastion_held_position_outro.5"] = { en = "It is what we teach. It is what I would have done.", ja = "" },  -- TODO
    ["line.bastion_held_position_outro.6"] = { en = "I have never watched it from outside before, and I do not know what I watched.", ja = "" },  -- TODO
    ["line.bastion_muster_intro.1"] = { en = "Another name off the roll. There is always another.", ja = "" },  -- TODO
    ["line.bastion_muster_intro.2"] = { en = "How long is the roll?", ja = "" },  -- TODO
    ["line.bastion_muster_intro.3"] = { en = "Longer than last season.", ja = "" },  -- TODO
    ["line.bastion_muster_outro.1"] = { en = "Shorter line at the muster tent this time.", ja = "" },  -- TODO
    ["line.bastion_muster_outro.2"] = { en = "That's the third season running.", ja = "" },  -- TODO
    ["line.bastion_muster_outro.3"] = { en = "Don't say anything about it, {name}. I have already heard what I would say.", ja = "" },  -- TODO
    ["line.bastion_relief_column_intro.1"] = { en = "Highwatch. Mountain post, top of the pass, warded on all four faces. It has been under siege for six weeks and without supply for twelve days.", ja = "" },  -- TODO
    ["line.bastion_relief_column_intro.2"] = { en = "The column carrying its winter stores and its ward-salt is sitting at the bottom of that mountain and cannot get up it.", ja = "" },  -- TODO
    ["line.bastion_relief_column_intro.3"] = { en = "Then they are still standing. Hold until relieved -- that is the order they were issued, and they will be keeping it.", ja = "" },  -- TODO
    ["line.bastion_relief_column_intro.4"] = { en = "Twelve days, Sworn. On a rock, in winter.", ja = "" },  -- TODO
    ["line.bastion_relief_column_intro.5"] = { en = "I have met men who held forty on a well that had gone dry.", ja = "" },  -- TODO
    ["line.bastion_relief_column_intro.6"] = { en = "...That is the assumption the order makes, yes.", ja = "" },  -- TODO
    ["line.bastion_relief_column_intro.7"] = { en = "The doctrine is hers. Acedia's. Everything I know about how to stand still and do nothing but wait, I learned off a woman who has been dead fifteen years.", ja = "" },  -- TODO
    ["line.bastion_relief_column_intro.8"] = { en = "{name}. This isn't your line and it isn't your order. There is no shame in leaving it to people who swore to it.", ja = "" },  -- TODO
    ["line.bastion_relief_column_intro.9"] = { en = "But I gave you two words in the ash, and I meant both of them. So.", ja = "" },  -- TODO
    ["line.bastion_relief_column_outro.1"] = { en = "Twelve days. We'd stopped counting somewhere around the eighth.", ja = "" },  -- TODO
    ["line.bastion_relief_column_outro.2"] = { en = "And they opened the gate to you.", ja = "" },  -- TODO
    ["line.bastion_relief_column_outro.3"] = { en = "Opened it? The sergeant came down the road on foot to meet the lead wagon. Wouldn't touch the flour. Went straight past me to the salt.", ja = "" },  -- TODO
    ["line.bastion_relief_column_outro.4"] = { en = "Their wards were four days from going out. Four days, and then that mountain is just a wall with tired men on it.", ja = "" },  -- TODO
    ["line.bastion_relief_column_outro.5"] = { en = "I gave the last of our water to the boy on the wagon on the ninth and told him a relief was coming. I didn't believe it when I said it.", ja = "" },  -- TODO
    ["line.bastion_relief_column_outro.6"] = { en = "But they held.", ja = "" },  -- TODO
    ["line.bastion_relief_column_outro.7"] = { en = "...Aye. They held.", ja = "" },  -- TODO
    ["line.bastion_relief_column_outro.8"] = { en = "Forgive me, {name}. I'm no use at this part of it.", ja = "" },  -- TODO
    ["line.bastion_relief_column_outro.9"] = { en = "Somebody arrived. That's all I have ever wanted a story to say.", ja = "" },  -- TODO
    ["line.bastion_the_long_list_confront.1"] = { en = "You've the look. Bastion. Sworn, by the shield.", ja = "" },  -- TODO
    ["line.bastion_the_long_list_confront.2"] = { en = "Whose name do you carry, then?", ja = "" },  -- TODO
    ["line.bastion_the_long_list_confront.3"] = { en = "Acedia's.", ja = "" },  -- TODO
    ["line.bastion_the_long_list_confront.4"] = { en = "Of course it is. They are still handing her out.", ja = "" },  -- TODO
    ["line.bastion_the_long_list_confront.5"] = { en = "Ask them where she is buried. Go on. Not what she did -- where she is buried.", ja = "" },  -- TODO
    ["line.bastion_the_long_list_confront.6"] = { en = "At Greywatch. Under the gate she died holding.", ja = "" },  -- TODO
    ["line.bastion_the_long_list_confront.7"] = { en = "Is she.", ja = "" },  -- TODO
    ["line.bastion_the_long_list_intro.1"] = { en = "The list. Knights who set their shields down. It is long, and we read it aloud.", ja = "" },  -- TODO
    ["line.bastion_the_long_list_intro.2"] = { en = "Every Oathkeeper shield in the order carries a name off that list. We read them so they are not forgotten.", ja = "" },  -- TODO
    ["line.bastion_the_long_list_intro.3"] = { en = "We read them so the entries can be closed.", ja = "" },  -- TODO
    ["line.bastion_the_long_list_intro.4"] = { en = "One of them is still walking about in our forms, calling himself a captain.", ja = "" },  -- TODO
    ["line.bastion_the_long_list_intro.5"] = { en = "...Then we close it.", ja = "" },  -- TODO
    ["line.bastion_the_long_list_outro.1"] = { en = "He was forsworn. Forsworn men lie -- that is very nearly the definition of the word.", ja = "" },  -- TODO
    ["line.bastion_the_long_list_outro.2"] = { en = "You don't get to set your shield down and then be believed about the woman who didn't.", ja = "" },  -- TODO
    ["line.bastion_the_long_list_outro.3"] = { en = "...", ja = "" },  -- TODO
    ["line.bastion_the_long_list_outro.4"] = { en = "He wasn't lying about a fact, though, was he. He asked me a question.", ja = "" },  -- TODO
    ["line.bastion_the_long_list_outro.5"] = { en = "Say nothing, {name}. I'm arguing with a dead man and I'd rather do it alone.", ja = "" },  -- TODO
    ["line.bastion_the_order_given_intro.1"] = { en = "The archive keeps everything. Including what it stopped reading.", ja = "" },  -- TODO
    ["line.bastion_the_order_given_intro.2"] = { en = "Greywatch. The relief order that was cut for it. I want the date on the seal.", ja = "" },  -- TODO
    ["line.bastion_the_order_given_intro.3"] = { en = "The archivist will not give you that.", ja = "" },  -- TODO
    ["line.bastion_the_order_given_intro.4"] = { en = "I know. That's why I'm bringing {name} and not a requisition.", ja = "" },  -- TODO
    ["line.bastion_the_order_given_outro.1"] = { en = "Here. The relief order cut for Greywatch. Sealed, dated, countersigned by two hands.", ja = "" },  -- TODO
    ["line.bastion_the_order_given_outro.10"] = { en = "I would rather have been late.", ja = "" },  -- TODO
    ["line.bastion_the_order_given_outro.11"] = { en = "Late is a thing a person can carry. Late means there was a door and I did not reach it in time, and a woman was on the other side of it holding.", ja = "" },  -- TODO
    ["line.bastion_the_order_given_outro.12"] = { en = "Take that away and I am not someone who was late. I am someone who built herself, brick by brick, out of an apology to a person who never needed one.", ja = "" },  -- TODO
    ["line.bastion_the_order_given_outro.13"] = { en = "So no. I'll keep the guilt, thank you.", ja = "" },  -- TODO
    ["line.bastion_the_order_given_outro.14"] = { en = "And we are not finished. Somebody in this order cut that seal, and somebody has been reading her name aloud ever since.", ja = "" },  -- TODO
    ["line.bastion_the_order_given_outro.2"] = { en = "Issued on the nineteenth.", ja = "" },  -- TODO
    ["line.bastion_the_order_given_outro.3"] = { en = "The gate was opened on the fourteenth.", ja = "" },  -- TODO
    ["line.bastion_the_order_given_outro.4"] = { en = "Five days, {name}. She opened it five days before anyone in this order was so much as ORDERED to come for her.", ja = "" },  -- TODO
    ["line.bastion_the_order_given_outro.5"] = { en = "There was no relief. There was nothing to be late for.", ja = "" },  -- TODO
    ["line.bastion_the_order_given_outro.6"] = { en = "\"Rowan. There was never anything you could have done.\"", ja = "" },  -- TODO
    ["line.bastion_the_order_given_outro.7"] = { en = "\"...\"", ja = "" },  -- TODO
    ["line.bastion_the_order_given_outro.8"] = { en = "Don't. Don't you hand me that.", ja = "" },  -- TODO
    ["line.bastion_the_order_given_outro.9"] = { en = "Say it. You want to say it. That I'm innocent, that I was sixteen, that the mule was not the problem.", ja = "" },  -- TODO
    ["line.bastion_turned_back_confront.1"] = { en = "Close enough. You've the walk. Which house?", ja = "" },  -- TODO
    ["line.bastion_turned_back_confront.10"] = { en = "They fed us. At the gate. Standing up.", ja = "" },  -- TODO
    ["line.bastion_turned_back_confront.11"] = { en = "And then a man I had trained beside told me there was no place, and could not look at the wall behind my head while he said it.", ja = "" },  -- TODO
    ["line.bastion_turned_back_confront.12"] = { en = "That is not how the order treats a knight who kept his oath.", ja = "" },  -- TODO
    ["line.bastion_turned_back_confront.13"] = { en = "No.", ja = "" },  -- TODO
    ["line.bastion_turned_back_confront.14"] = { en = "It isn't.", ja = "" },  -- TODO
    ["line.bastion_turned_back_confront.15"] = { en = "...Then what did you do that they would not have you back?", ja = "" },  -- TODO
    ["line.bastion_turned_back_confront.16"] = { en = "I have spent fifteen years telling that to people who decided I was a liar before I opened my mouth. You've a sword out and the order's coin in your pocket. You'll forgive me if I don't spend the breath.", ja = "" },  -- TODO
    ["line.bastion_turned_back_confront.17"] = { en = "Ask them. Ask them why we couldn't come home, and watch which way they look while they answer.", ja = "" },  -- TODO
    ["line.bastion_turned_back_confront.18"] = { en = "Now. We've taken no lives on this road and we don't intend to start. But we're not being taken either, so make your peace and come on.", ja = "" },  -- TODO
    ["line.bastion_turned_back_confront.2"] = { en = "The Bastion.", ja = "" },  -- TODO
    ["line.bastion_turned_back_confront.3"] = { en = "...Of course. They still send them out one at a time.", ja = "" },  -- TODO
    ["line.bastion_turned_back_confront.4"] = { en = "You keep a picket line. You've a camp laid out in quarters and a man on the high ground. Bandits do not do that.", ja = "" },  -- TODO
    ["line.bastion_turned_back_confront.5"] = { en = "No. They don't.", ja = "" },  -- TODO
    ["line.bastion_turned_back_confront.6"] = { en = "You were sworn.", ja = "" },  -- TODO
    ["line.bastion_turned_back_confront.7"] = { en = "Sixty of us. On a gate. A long way east of anywhere your quartermaster has been.", ja = "" },  -- TODO
    ["line.bastion_turned_back_confront.8"] = { en = "Then you deserted it.", ja = "" },  -- TODO
    ["line.bastion_turned_back_confront.9"] = { en = "Girl, I walked to the nearest chapter house of your order with what was left of my company behind me, and I stood in the yard for two days.", ja = "" },  -- TODO
    ["line.bastion_turned_back_intro.1"] = { en = "A crew on the eastern road. Six wagons in a season, no lives taken, nothing burned.", ja = "" },  -- TODO
    ["line.bastion_turned_back_intro.10"] = { en = "...As you say.", ja = "" },  -- TODO
    ["line.bastion_turned_back_intro.11"] = { en = "{name} -- a word before we go.", ja = "" },  -- TODO
    ["line.bastion_turned_back_intro.12"] = { en = "Every quarter I have served, the order has wanted men like that alive and talking. You bring in a deserter, you read him the list, he goes back on the line where he is some use.", ja = "" },  -- TODO
    ["line.bastion_turned_back_intro.13"] = { en = "I have never once been told to end one.", ja = "" },  -- TODO
    ["line.bastion_turned_back_intro.14"] = { en = "It will be in the reports somewhere and I will find it when we're back. Come on.", ja = "" },  -- TODO
    ["line.bastion_turned_back_intro.2"] = { en = "That is not a crew, that is a garrison. Who are they?", ja = "" },  -- TODO
    ["line.bastion_turned_back_intro.3"] = { en = "Road-men.", ja = "" },  -- TODO
    ["line.bastion_turned_back_intro.4"] = { en = "Road-men leave bodies.", ja = "" },  -- TODO
    ["line.bastion_turned_back_intro.5"] = { en = "These are to be ended, Squire. Not brought in. Ended.", ja = "" },  -- TODO
    ["line.bastion_turned_back_intro.6"] = { en = "\"You know who they are, don't you.\"", ja = "" },  -- TODO
    ["line.bastion_turned_back_intro.7"] = { en = "\"Six wagons. That's it?\"", ja = "" },  -- TODO
    ["line.bastion_turned_back_intro.8"] = { en = "I know what the contract says. So do you.", ja = "" },  -- TODO
    ["line.bastion_turned_back_intro.9"] = { en = "Six that were reported. Take the work or leave it on the board.", ja = "" },  -- TODO
    ["line.bastion_turned_back_outro.1"] = { en = "He had a picket rotation. He had his camp laid out in quarters and a man on the high ground.", ja = "" },  -- TODO
    ["line.bastion_turned_back_outro.10"] = { en = "That is why I am the way I am. In case you had wondered and were too polite to ask.", ja = "" },  -- TODO
    ["line.bastion_turned_back_outro.11"] = { en = "Let's go back. I want to read that contract.", ja = "" },  -- TODO
    ["line.bastion_turned_back_outro.2"] = { en = "I have buried knights who did it worse and been told to write commendations over them.", ja = "" },  -- TODO
    ["line.bastion_turned_back_outro.3"] = { en = "{name}, I want you to hear me say it while it is still fresh enough to be honest: I do not know what we did tonight.", ja = "" },  -- TODO
    ["line.bastion_turned_back_outro.4"] = { en = "The order said end them. So they are ended. That is the entire paperwork.", ja = "" },  -- TODO
    ["line.bastion_turned_back_outro.5"] = { en = "...", ja = "" },  -- TODO
    ["line.bastion_turned_back_outro.6"] = { en = "I was sixteen the first time I went out on a rotation. Relief column, the eastern posts. My whole duty was the water -- four skins on a mule, and I checked them at every halt like they were relics.", ja = "" },  -- TODO
    ["line.bastion_turned_back_outro.7"] = { en = "We were eleven miles out when the word came back down the line. The post was already gone. Turn around.", ja = "" },  -- TODO
    ["line.bastion_turned_back_outro.8"] = { en = "So we turned around, and I carried four full skins all the way home.", ja = "" },  -- TODO
    ["line.bastion_turned_back_outro.9"] = { en = "Fifteen years, and I have never once set down a full waterskin without finding out first who needed it.", ja = "" },  -- TODO
    ["line.bastion_what_the_bastion_knows_intro.1"] = { en = "I want to ask the order a question.", ja = "" },  -- TODO
    ["line.bastion_what_the_bastion_knows_intro.2"] = { en = "Ask it.", ja = "" },  -- TODO
    ["line.bastion_what_the_bastion_knows_intro.3"] = { en = "Did you know.", ja = "" },  -- TODO
    ["line.bastion_what_the_bastion_knows_intro.4"] = { en = "...", ja = "" },  -- TODO
    ["line.bastion_what_the_bastion_knows_intro.5"] = { en = "Take the quest, Sworn.", ja = "" },  -- TODO
    ["line.bastion_what_the_bastion_knows_outro.1"] = { en = "We knew. The terms are under seal in the second vault and they have been since the year it happened.", ja = "" },  -- TODO
    ["line.bastion_what_the_bastion_knows_outro.10"] = { en = "We shall hold.", ja = "" },  -- TODO
    ["line.bastion_what_the_bastion_knows_outro.2"] = { en = "She negotiated. Her life and her company's lives, for the gate. There was no siege. There was no desperate hour. It was a transaction and she got her price.", ja = "" },  -- TODO
    ["line.bastion_what_the_bastion_knows_outro.3"] = { en = "We weighed a hard truth against a useful saint, knight, and we took the one that keeps the posts manned.", ja = "" },  -- TODO
    ["line.bastion_what_the_bastion_knows_outro.4"] = { en = "Every man on that line holds because he can say her name. What would you have had us do?", ja = "" },  -- TODO
    ["line.bastion_what_the_bastion_knows_outro.5"] = { en = "...", ja = "" },  -- TODO
    ["line.bastion_what_the_bastion_knows_outro.6"] = { en = "{name}. Walk with me. Not far.", ja = "" },  -- TODO
    ["line.bastion_what_the_bastion_knows_outro.7"] = { en = "I swore to you in the ash and I never asked you whether you wanted it.", ja = "" },  -- TODO
    ["line.bastion_what_the_bastion_knows_outro.8"] = { en = "I would have sworn it to anyone burning that night. Anyone at all. That is not devotion, that is a reflex with a nice sentence on it, and I have been calling it my honour for a year.", ja = "" },  -- TODO
    ["line.bastion_what_the_bastion_knows_outro.9"] = { en = "So. Again, and properly this time. Not to an order. Not to a name off a shield. To you -- because I have looked at you and chosen, and I could have chosen otherwise.", ja = "" },  -- TODO
    ["line.cathedral_fallen_confessor_confront.1"] = { en = "The one before you wore our cloth. Confessor. Anointed. She knows the charge.", ja = "" },  -- TODO
    ["line.cathedral_fallen_confessor_confront.2"] = { en = "She sheltered what was ours to reclaim, and would not give it back. That is theft from the faith. Purge her, and be paid.", ja = "" },  -- TODO
    ["line.cathedral_fallen_confessor_confront.3"] = { en = "They were children. The faith did not ask them. It has never once asked.", ja = "" },  -- TODO
    ["line.cathedral_fallen_confessor_confront.4"] = { en = "And now it sends you to take me. I understand. Take is the only verb they were ever taught.", ja = "" },  -- TODO
    ["line.cathedral_fallen_confessor_confront.5"] = { en = "I will not step aside, and I will not strike first. Come, then.", ja = "" },  -- TODO
    ["line.cathedral_fallen_confessor_confront.6"] = { en = "Take what you can. You will find I have already given it away.", ja = "" },  -- TODO
    ["line.cathedral_general_lust_confront.1"] = { en = "You came back. In their colors, a blade at your back. I could take the blade. I could take them.", ja = "" },  -- TODO
    ["line.cathedral_general_lust_confront.2"] = { en = "Not you. I have never once been able to take you. You know why.", ja = "" },  -- TODO
    ["line.cathedral_general_lust_confront.3"] = { en = "There is nothing left in there to hold. They emptied you, sister, the same as me. I kept what I took. You gave yours away, so that no one ever could.", ja = "" },  -- TODO
    ["line.cathedral_general_lust_confront.4"] = { en = "So let me give, for once. The one thing you never let yourself want back.", ja = "" },  -- TODO
    ["line.cathedral_general_lust_confront.5"] = { en = "I know the name you were born with -- before the cloth, before they renamed you for a virtue you could be worked to death inside. Kneel, and it is yours again.", ja = "" },  -- TODO
    ["line.cathedral_general_lust_confront.6"] = { en = "...", ja = "" },  -- TODO
    ["line.cathedral_general_lust_confront.7"] = { en = "That name is not yours to give. Taking it back from your hand would only be one more theft.", ja = "" },  -- TODO
    ["line.cathedral_general_lust_confront.8"] = { en = "I know what I am called. I gave it to myself. And that, I am keeping.", ja = "" },  -- TODO
    ["line.colosseum_debut_confront.1"] = { en = "Opening bout! On the sand -- nobody, no house, no record.", ja = "" },  -- TODO
    ["line.colosseum_debut_confront.2"] = { en = "And against them, on hire from no one in particular: Saber.", ja = "" },  -- TODO
    ["line.colosseum_debut_confront.3"] = { en = "On hire from whoever paid, thank you. It's a living.", ja = "" },  -- TODO
    ["line.colosseum_debut_confront.4"] = { en = "Right. You've not done this before, so -- two things, free, because I'd rather it was a bout than a mess.", ja = "" },  -- TODO
    ["line.colosseum_debut_confront.5"] = { en = "One. The crowd is not on your side and it is not against you. It does not know you exist yet. Stop listening to it.", ja = "" },  -- TODO
    ["line.colosseum_debut_confront.6"] = { en = "Two.", ja = "" },  -- TODO
    ["line.colosseum_debut_confront.7"] = { en = "Everyone your size opens careful. Feels each other out, three or four exchanges, learns the range.", ja = "" },  -- TODO
    ["line.colosseum_debut_confront.8"] = { en = "I don't.", ja = "" },  -- TODO
    ["line.conversation_wrath_intro.1"] = { en = "So. Fresh blood for the sand. The crowd does love a debut -- win or die.", ja = "ほう、砂場に新しい血か。観衆はデビュー戦が大好きだ――勝つか、死ぬかだ。" },
    ["line.conversation_wrath_intro.2"] = { en = "We came to fight, not to be entertainment.", ja = "戦いに来た。見世物になりに来たわけじゃない。" },
    ["line.conversation_wrath_intro.3"] = { en = "Here they are the same thing. Tell me -- why should the arena remember your name?", ja = "ここでは同じことさ。言ってみろ――なぜ闘技場がお前の名を覚えるべきなのか?" },
    ["line.conversation_wrath_intro.4"] = { en = "\"Because we fight for coin.\"", ja = "「金のために戦うからだ。」" },
    ["line.conversation_wrath_intro.5"] = { en = "\"Because we fight for honor.\"", ja = "「誇りのために戦うからだ。」" },
    ["line.conversation_wrath_intro.6"] = { en = "Honest, at least. The purse is yours if you live.", ja = "少なくとも正直だな。生き延びれば賞金はお前のものだ。" },
    ["line.conversation_wrath_intro.7"] = { en = "Honor. The crowd will cheer it and forget it by morning.", ja = "誇りか。観衆は歓声を上げ、朝には忘れるだろう。" },
    ["line.conversation_wrath_intro.8"] = { en = "Then let us be quick about it. The Light is watching, even here.", ja = "では手短に済ませよう。光はここでも見ておられる。" },
    ["line.conversation_wrath_intro.9"] = { en = "Watching, and unimpressed. Open the gate.", ja = "見ていて、しかも呆れているがな。門を開けろ。" },
    ["line.flight_champion.1"] = { en = "Stop here, {name}. That one at the head of them is no imp -- it has a name where they carry none, and it leads this whole raiding party. This is the thing that has been walking the road behind us.", ja = "" },  -- TODO
    ["line.flight_champion.2"] = { en = "It's between us and the capital.", ja = "" },  -- TODO
    ["line.flight_champion.3"] = { en = "It is. And it will not fall to the swarm-work that served against the rest -- it takes blows the grunts could not, and the imps beside it only want to keep us busy while it reaches you.", ja = "" },  -- TODO
    ["line.flight_champion.4"] = { en = "Then we cut it down and the imps stop mattering.", ja = "" },  -- TODO
    ["line.flight_champion.5"] = { en = "Just so. Put it down and the road opens. Stay off its reach, let it come onto our line, and we end this at the gate rather than inside it. Ready when you are.", ja = "" },  -- TODO
    ["line.flight_event_shrine.1"] = { en = "A wayside shrine, still standing where everything around it burned.", ja = "" },  -- TODO
    ["line.flight_event_shrine.2"] = { en = "Someone tended it to the last. It feels wrong to walk straight past. Choose...", ja = "" },  -- TODO
    ["line.flight_event_shrine.3"] = { en = "Kneel and pray for the road ahead.", ja = "" },  -- TODO
    ["line.flight_event_shrine.4"] = { en = "Take the traveller's offering left at its foot.", ja = "" },  -- TODO
    ["line.flight_event_shrine.5"] = { en = "...steadier. Whatever waits up the road, my hands are steadier for it.", ja = "" },  -- TODO
    ["line.flight_event_shrine.6"] = { en = "Flasks, wrapped against the damp -- left for whoever came after. That is us now. Carry them.", ja = "" },  -- TODO
    ["line.flight_event_shrine.7"] = { en = "The capital, then. Keep moving.", ja = "" },  -- TODO
    ["line.flight_event_survivor.1"] = { en = "Hold. Someone's in the brush -- hurt, and trying not to be heard.", ja = "" },  -- TODO
    ["line.flight_event_survivor.2"] = { en = "Easy. We're not with the things that did this. Choose...", ja = "" },  -- TODO
    ["line.flight_event_survivor.3"] = { en = "Ask which way the demons went.", ja = "" },  -- TODO
    ["line.flight_event_survivor.4"] = { en = "Share what little we carry, and press on.", ja = "" },  -- TODO
    ["line.flight_event_survivor.5"] = { en = "...north, along the ridge, in numbers. Good. We take the low road, then.", ja = "" },  -- TODO
    ["line.flight_event_survivor.6"] = { en = "They pressed a torch on us for the kindness -- said the low road is dark by dusk. Take it.", ja = "" },  -- TODO
    ["line.flight_event_survivor.7"] = { en = "Go carefully. The capital's walls still stand -- reach them.", ja = "" },  -- TODO
    ["line.prologue_arrival.1"] = { en = "There it is. Walls still standing, gates still shut. The capital.", ja = "" },  -- TODO
    ["line.prologue_arrival.10"] = { en = "It's been like this for weeks. The demons push, a village burns, and everyone still breathing runs for the capital. The city's fit to burst, work's gone dry, and food with it.", ja = "" },  -- TODO
    ["line.prologue_arrival.11"] = { en = "But coin still moves for those who can hold a blade. Register with the Adventurers' Guild -- the quest board takes anyone who'll take a contract. Pays a good deal better than queuing for bread.", ja = "" },  -- TODO
    ["line.prologue_arrival.12"] = { en = "Work that pays. That, we can do.", ja = "" },  -- TODO
    ["line.prologue_arrival.13"] = { en = "The board, then. We'll want coin before we want anything else.", ja = "" },  -- TODO
    ["line.prologue_arrival.2"] = { en = "The Bastion holds this wall. If anywhere is still holding, {name}, it is behind these stones.", ja = "" },  -- TODO
    ["line.prologue_arrival.3"] = { en = "More of them. Third column through the gate since morning -- where are we meant to put them all?", ja = "" },  -- TODO
    ["line.prologue_arrival.4"] = { en = "Not under my roof, that's certain. Barely bread enough for the mouths already inside.", ja = "" },  -- TODO
    ["line.prologue_arrival.5"] = { en = "You there -- off the road, with the others. Nobody passes until they're processed. Names, and where you've run from.", ja = "" },  -- TODO
    ["line.prologue_arrival.6"] = { en = "Papers, a token, a seal, anything to say who you are. No? Then you'll wait like the rest of them until I say oth--", ja = "" },  -- TODO
    ["line.prologue_arrival.7"] = { en = "...That plate. That's Bastion steel. You're a sworn knight of the Order?", ja = "" },  -- TODO
    ["line.prologue_arrival.8"] = { en = "I held the eastern wall. The wall is ash now. I brought out who I could.", ja = "" },  -- TODO
    ["line.prologue_arrival.9"] = { en = "Forgive me, ser. We don't see many of the Order come through on foot these days. Pass -- you, and the ones at your back.", ja = "" },  -- TODO
    ["line.prologue_flee.1"] = { en = "It's gone. All of it. My oath was to this ground, and the ground is ash.", ja = "" },  -- TODO
    ["line.prologue_flee.2"] = { en = "So I swear a new one, and not to ground this time. To you.", ja = "" },  -- TODO
    ["line.prologue_flee.3"] = { en = "We shall hold.", ja = "" },  -- TODO
    ["line.prologue_flee.4"] = { en = "To the capital, then. Its walls still stand... for now.", ja = "" },  -- TODO
    ["line.prologue_flier.1"] = { en = "Bounties, escorts, standing contracts... half of these want a company three times our size.", ja = "" },  -- TODO
    ["line.prologue_flier.2"] = { en = "This one doesn't.", ja = "" },  -- TODO
    ["line.prologue_flier.3"] = { en = "The Colosseum. They pay for a debut bout -- a single fight, on the sand, in front of a crowd. Win or lose, the purse is posted the same.", ja = "" },  -- TODO
    ["line.prologue_flier.4"] = { en = "A blood sport.", ja = "" },  -- TODO
    ["line.prologue_flier.5"] = { en = "A paying one, and it asks only two on the field. It is not the war we came to fight, {name}... but it is the coin we can earn today. Take it, and we eat.", ja = "" },  -- TODO
    ["line.prologue_intro.1"] = { en = "Fire on the eastern fields -- demons, real ones, not a soldier's tale! Run, child, run!", ja = "" },  -- TODO
    ["line.prologue_intro.2"] = { en = "{name}. Behind me, and stay there. This is the part of the oath I have been waiting to keep.", ja = "" },  -- TODO
    ["line.prologue_intro.3"] = { en = "They serve the Demon Lord. If the capital falls after us, there is nowhere left to run to.", ja = "" },  -- TODO
    ["line.prologue_intro.4"] = { en = "Then we hold this lane. You have watched me drill this a hundred times, {name} -- now you do it. Move when I move, strike what I strike.", ja = "" },  -- TODO
    ["line.prologue_ruins.1"] = { en = "I can still see the smoke from here. That's not just our roofs, is it.", ja = "" },  -- TODO
    ["line.prologue_ruins.10"] = { en = "I am certain of the walls. I am less certain of the road -- the army that did this is walking it too, and it is not in a hurry. Stay close, {name}, and we will get there before they do.", ja = "" },  -- TODO
    ["line.prologue_ruins.2"] = { en = "No. Look past the fords -- every steading down the valley is burning, and the ones that aren't are already cold. They came through the whole of it in a night.", ja = "" },  -- TODO
    ["line.prologue_ruins.3"] = { en = "Then there are others. People who ran, like we ran.", ja = "" },  -- TODO
    ["line.prologue_ruins.4"] = { en = "Almost certainly. Scattered, hiding, no idea which way is safe.", ja = "" },  -- TODO
    ["line.prologue_ruins.5"] = { en = "We find them. I'm not walking past someone who's still out there.", ja = "" },  -- TODO
    ["line.prologue_ruins.6"] = { en = "Good. That is the right instinct, and I would have argued you into it if you hadn't got there first. We take who we find, and we keep moving while we do it.", ja = "" },  -- TODO
    ["line.prologue_ruins.7"] = { en = "Moving where? There's nothing left behind us.", ja = "" },  -- TODO
    ["line.prologue_ruins.8"] = { en = "The capital. Its walls are the last ones standing between here and the sea, and they hold a great deal more than a village gate.", ja = "" },  -- TODO
    ["line.prologue_ruins.9"] = { en = "You don't sound certain.", ja = "" },  -- TODO
    ["line.prologue_victory.1"] = { en = "Enough -- enough! It's been years since anyone put me on my back on this sand.", ja = "" },  -- TODO
    ["line.prologue_victory.2"] = { en = "I've watched this place feed fighters to its patron, one after another. I will not be fed. But you two, I'll follow. There's a reckoning owed beneath this arena, and I mean to collect it.", ja = "" },  -- TODO
    ["line.prologue_victory.3"] = { en = "Well fought. The Adventurers' Guild is always short of people who live through their first bout.", ja = "" },  -- TODO
    ["line.prologue_victory.4"] = { en = "You want the Demon Lord? So does everyone who's lost a home. But it is only strong because of its seven -- its generals, its appetites. Unmake them one by one, and the crown is hollow. The board is open to you. Start climbing.", ja = "" },  -- TODO
    ["line.prologue_village.1"] = { en = "Look at it, {name}. The mill, the eastern row, the well we drew from this morning -- all of it, inside a night.", ja = "" },  -- TODO
    ["line.prologue_village.2"] = { en = "This is not a raid. The Demon Lord's army empties whole valleys like this and moves on before the ash is cold.", ja = "" },  -- TODO
    ["line.prologue_village.3"] = { en = "Two of them have seen us, and they will not come to you. Watch how I take mine.", ja = "" },  -- TODO
    ["line.tutorial_flight.1"] = { en = "Walk to the chest ahead -- use WASD, the arrow keys, or click a tile.", ja = "" },  -- TODO
    ["line.tutorial_flight.2"] = { en = "Open your loadout to see what you found.", ja = "" },  -- TODO
    ["line.tutorial_flight.3"] = { en = "{select} an item in your stash to equip it to a hero.", ja = "" },  -- TODO
    ["line.tutorial_village.1"] = { en = "Like that. Now yours, {name} -- close the ground and put it down.", ja = "" },  -- TODO
    ["line.tutorial_village.10"] = { en = "{select} on the lit tile to move there.", ja = "" },  -- TODO
    ["line.tutorial_village.11"] = { en = "{select} on Clear Out in your grid to ready it.", ja = "" },  -- TODO
    ["line.tutorial_village.12"] = { en = "{select} on your own tile to spin.", ja = "" },  -- TODO
    ["line.tutorial_village.13"] = { en = "{select} on Jolt to ready it. Its cost is purple: that is mana, not stamina.", ja = "" },  -- TODO
    ["line.tutorial_village.14"] = { en = "{select} on the grunt to jolt it.", ja = "" },  -- TODO
    ["line.tutorial_village.15"] = { en = "{select} on the grunt to strike it -- its card slid down the order, so you act before it does.", ja = "" },  -- TODO
    ["line.tutorial_village.2"] = { en = "More of them, and they will not come near enough for a blade. Use your techniques. Get in among those two, where both can reach you.", ja = "" },  -- TODO
    ["line.tutorial_village.3"] = { en = "Now take it in hand.", ja = "" },  -- TODO
    ["line.tutorial_village.4"] = { en = "Turn on your heel, {name}. Open them both at once.", ja = "" },  -- TODO
    ["line.tutorial_village.5"] = { en = "That one is bigger. Take this too -- I never had the knack for it, and you may. It draws on something you have far less of than breath, so you get one.", ja = "" },  -- TODO
    ["line.tutorial_village.6"] = { en = "Let it have the spark. It will not know which way it is facing.", ja = "" },  -- TODO
    ["line.tutorial_village.7"] = { en = "There -- it is reeling, and you are not. That is what the spark bought you: a turn it does not get. Finish it, {name}.", ja = "" },  -- TODO
    ["line.tutorial_village.8"] = { en = "Not that, {name}. Do as I showed you.", ja = "" },  -- TODO
    ["line.tutorial_village.9"] = { en = "{select} on the imp to move in range and attack with your weapon.", ja = "" },  -- TODO
